/**
 * Show a SweetAlert2 Toast alert.
 * @param {string} message - The message to display in the toast alert.
 * @param {"SweetAlert2.ENUM_SweetAlert2_Status.success"|"SweetAlert2.ENUM_SweetAlert2_Status.error"|"SweetAlert2.ENUM_SweetAlert2_Status.warning"|"SweetAlert2.ENUM_SweetAlert2_Status.info"|"SweetAlert2.ENUM_SweetAlert2_Status.question"} statusType - The status type of the notification. E.g. Success, Warning, Error, etc.
 * @param {Big} timer - How long the toast will stay on the screen, in milliseconds. Will be infinite if set to 'empty'.
 * @param {boolean} timerProgressBar - Show a progress bar for timer.
 * @param {"SweetAlert2.ENUM_SweetAlert2_Position.top"|"SweetAlert2.ENUM_SweetAlert2_Position.top_start"|"SweetAlert2.ENUM_SweetAlert2_Position.top_end"|"SweetAlert2.ENUM_SweetAlert2_Position.center"|"SweetAlert2.ENUM_SweetAlert2_Position.center_start"|"SweetAlert2.ENUM_SweetAlert2_Position.center_end"|"SweetAlert2.ENUM_SweetAlert2_Position.bottom"|"SweetAlert2.ENUM_SweetAlert2_Position.bottom_start"|"SweetAlert2.ENUM_SweetAlert2_Position.bottom_end"} position - Position of element on the page.
 * @param {boolean} showCloseButton - Display a clickable close button.
 * @returns {Promise.<boolean>}
 */
export async function JS_ShowToastAlert(message, statusType, timer, timerProgressBar, position, showCloseButton) {
	// BEGIN USER CODE
	try {
		const Toast = Swal.mixin({
			toast: true,
			position: position.replace('_','-'),
			showConfirmButton: false,
			showCloseButton: showCloseButton,
			timer: timer,
			timerProgressBar: timerProgressBar,
			didOpen: (toast) => {
				toast.addEventListener('mouseenter', Swal.stopTimer)
				toast.addEventListener('mouseleave', Swal.resumeTimer)
			}
		})

		Toast.fire({
			icon: statusType,
			title: message,
			showClass: {
				popup: `
				animate__animated
				animate__fadeInRight
				animate__faster
			  `,
			  },
			  hideClass: {
				popup: `
				animate__animated
				animate__fadeOutRight
				animate__faster
			  `,
			  },
		})
	}
	catch(err)
	{
		alert("Error firing alert.");
	}
	// END USER CODE
}
